// OK: 命名で意図を表現
function calculateBillingAmount(
  user: User,
  billingDate: Date
): Money {
  const trialPeriodDays = 14;
  const isInTrialPeriod =
    daysBetween(user.trialStartDate, billingDate)
    <= trialPeriodDays;
  return isInTrialPeriod ? Money.zero() : user.plan.monthlyFee;
}
